@@ -1461,6 +1461,8 @@
-        // Set NOOUTERTHIS for all synthetic outer instance variables, and unset
-        // it when the variable is accessed. If the variable is never accessed,
-        // we skip creating an outer instance field and saving the constructor
-        // parameter to it.
-        VarSymbol outerThis =
-            new VarSymbol(flags | NOOUTERTHIS, outerThisName(target, owner), target, owner);
+        if (owner.kind == TYP) {
+            // Set NOOUTERTHIS for all synthetic outer instance variables, and unset
+            // it when the variable is accessed. If the variable is never accessed,
+            // we skip creating an outer instance field and saving the constructor
+            // parameter to it.
+            flags = flags | NOOUTERTHIS | OUTER_THIS_FIELD;
+        }
+        VarSymbol outerThis = new VarSymbol(flags, outerThisName(target, owner), target, owner);

@@ -594,7 +594,7 @@
-                for (JCVariableDecl param : md.params) {
-                    if (param.name == tree.name &&
-                            tree.sym.isSynthetic() &&
-                            tree.sym.kind == VAR &&
-                            tree.sym.owner == md.sym.enclClass()) {
-                        tree.sym = param.sym;
-                    }
+                if ((tree.sym.flags() & OUTER_THIS_FIELD) != 0) {
+                    tree.sym = md.sym.extraParams.head;
+                } else if ((tree.sym.flags() & LOCAL_CAPTURE_FIELD) != 0) {
+                    Symbol capturedSym = tree.sym.baseSymbol();
+                    tree.sym = md.sym.capturedLocals.stream()
+                            .filter(l -> l.baseSymbol() == capturedSym)
+                            .findAny().orElseThrow();
@@ -604,3 +604,5 @@
-        EarlyInitializerVisitor initializerVisitor = new EarlyInitializerVisitor();
-        for (JCStatement init : initCode) {
-            initializerVisitor.scan(init);
+        if (md.sym.capturedLocals.nonEmpty() || md.sym.extraParams.nonEmpty()) {
+            EarlyInitializerVisitor initializerVisitor = new EarlyInitializerVisitor();
+            for (JCStatement init : initCode) {
+                initializerVisitor.scan(init);
+            }
